const data = $input.first().json;
const riskEmoji = data.risk_level === 'critical' ? '🚨' : data.risk_level === 'high' ? '⚠️' : '🔔';
const message = `${riskEmoji} APROBACIÓN REQUERIDA — ${data.brand_id.toUpperCase()}
Tipo: ${data.action_type}
Riesgo: ${data.risk_level.toUpperCase()}

Contexto:
${data.reason}

Respuesta sugerida:
"${data.draft_response || 'Ver payload'}"

Opciones:
✅ APROBAR → Responder OK
✏️ EDITAR → Enviar texto corregido
❌ RECHAZAR → Responder NO

Expira en: ${data.risk_level === 'critical' ? '15 minutos' : data.risk_level === 'high' ? '2 horas' : '24 horas'}`;
return { ...data, alert_message: message };
